/**
 * MarketBreadthMonitor.js
 *
 * Stockbee Market Monitor table for Power Theme.
 * Reads from /breadth_monitor.json (generated by breadth_monitor.py).
 *
 * Columns: DATE | UP 4%+ | DN 4%+ | 5D R | 10D R |
 *          UP 25% Q | DN 25% Q | UP 25% M | DN 25% M |
 *          UP 50% M | DN 50% M | UP 13% 34D | DN 13% 34D |
 *          10x ATR Ext | >50 DMA | Share Universe | T2108 | S&P
 */

import { memo, useCallback, useEffect, useRef, useState } from "react";
import { BarChart3, Check, Clipboard, Copy, Download, ExternalLink, RefreshCw, Trash2, X } from "lucide-react";
import BreadthStockModal from "./BreadthStockModal";

// ---------------------------------------------------------------------------
// Constants
// ---------------------------------------------------------------------------

const BULLISH_FILTERS = new Set(["up4", "up25q", "up25m", "up50m", "up13_34", "above50dma"]);

// ---------------------------------------------------------------------------
// WatchlistClipboard panel
// ---------------------------------------------------------------------------

const WatchlistClipboard = memo(function WatchlistClipboard({ groups, onRemoveGroup, onClear, onClose }) {
  const [tab, setTab]       = useState("bullish");
  const [copied, setCopied] = useState(false);
  const timerRef            = useRef(null);

  const bullish = groups.filter((g) => g.sentiment === "bullish");
  const bearish = groups.filter((g) => g.sentiment === "bearish");
  const active  = tab === "bullish" ? bullish : bearish;

  const allTickers = active.flatMap((g) => g.tickers);
  const uniqueTickers = [...new Set(allTickers)];

  const handleCopy = () => {
    if (!uniqueTickers.length) return;
    navigator.clipboard.writeText(uniqueTickers.join(",")).then(() => {
      setCopied(true);
      clearTimeout(timerRef.current);
      timerRef.current = setTimeout(() => setCopied(false), 1800);
    });
  };

  const handleDownload = () => {
    if (!uniqueTickers.length) return;
    const csv = "Ticker\n" + uniqueTickers.join("\n");
    const blob = new Blob([csv], { type: "text/csv" });
    const url  = URL.createObjectURL(blob);
    const a    = document.createElement("a");
    a.href = url; a.download = `${tab}_tickers.csv`; a.click();
    URL.revokeObjectURL(url);
  };

  useEffect(() => () => clearTimeout(timerRef.current), []);

  return (
    <div className="absolute right-0 top-full mt-1 z-50 w-80 rounded-xl border border-zinc-700 bg-zinc-900 shadow-2xl">
      {/* Header */}
      <div className="flex items-center justify-between border-b border-zinc-800 px-3 py-2">
        <span className="text-xs font-semibold text-zinc-300">Watchlist Clipboard</span>
        <button onClick={onClose} className="rounded p-0.5 text-zinc-500 hover:text-zinc-200">
          <X className="h-3.5 w-3.5" />
        </button>
      </div>

      {/* Tabs */}
      <div className="flex gap-1 border-b border-zinc-800 px-3 py-2">
        <button
          onClick={() => setTab("bullish")}
          className={`rounded-full px-3 py-0.5 text-xs font-medium transition-colors
            ${tab === "bullish" ? "bg-emerald-600 text-white" : "bg-zinc-800 text-zinc-400 hover:text-zinc-200"}`}
        >
          Bullish ({bullish.reduce((s, g) => s + g.tickers.length, 0)})
        </button>
        <button
          onClick={() => setTab("bearish")}
          className={`rounded-full px-3 py-0.5 text-xs font-medium transition-colors
            ${tab === "bearish" ? "bg-rose-600 text-white" : "bg-zinc-800 text-zinc-400 hover:text-zinc-200"}`}
        >
          Bearish ({bearish.reduce((s, g) => s + g.tickers.length, 0)})
        </button>
      </div>

      {/* Groups */}
      <div className="max-h-56 overflow-y-auto">
        {active.length === 0 ? (
          <p className="py-6 text-center text-xs text-zinc-600">No {tab} tickers yet.</p>
        ) : (
          active.map((g) => (
            <div key={g.id} className="border-b border-zinc-800/60 px-3 py-2">
              {/* Group label row */}
              <div className="flex items-center justify-between mb-1">
                <span className="text-xs font-semibold text-zinc-200">{g.label}</span>
                <div className="flex items-center gap-2">
                  <span className="text-xs text-zinc-500">{g.tickers.length}</span>
                  <button
                    onClick={() => onRemoveGroup(g.id)}
                    className="text-zinc-600 hover:text-rose-400 transition-colors"
                  >
                    <X className="h-3 w-3" />
                  </button>
                </div>
              </div>
              {/* Tickers text */}
              <p className="text-[11px] leading-relaxed text-zinc-400 break-all">
                {g.tickers.join(",")}
              </p>
            </div>
          ))
        )}
      </div>

      {/* Footer actions */}
      <div className="flex items-center justify-between border-t border-zinc-800 px-3 py-2">
        <button
          onClick={handleCopy}
          className="flex items-center gap-1 text-xs text-zinc-400 hover:text-zinc-200 transition-colors"
        >
          {copied ? <Check className="h-3 w-3 text-emerald-400" /> : <Copy className="h-3 w-3" />}
          {copied ? "Copied!" : "Copy"}
        </button>
        <button
          onClick={handleDownload}
          className="flex items-center gap-1 text-xs text-zinc-400 hover:text-zinc-200 transition-colors"
        >
          <Download className="h-3 w-3" />
          Download CSV
        </button>
        <button
          onClick={() => onClear(tab)}
          className="flex items-center gap-1 text-xs text-zinc-400 hover:text-rose-400 transition-colors"
        >
          <Trash2 className="h-3 w-3" />
          Clear
        </button>
      </div>
    </div>
  );
});

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

function fmtN(n) {
  if (n == null || !Number.isFinite(n)) return "—";
  return Number.isInteger(n) ? String(n) : n.toFixed(2);
}

function t2108Badge(v) {
  if (v == null || !Number.isFinite(v)) return null;
  if (v < 20) return { label: "Oversold (<20)", cls: "bg-rose-900/60 text-rose-300" };
  if (v > 70) return { label: "Overbought (>70)", cls: "bg-amber-900/60 text-amber-300" };
  return { label: "Neutral (20–70)", cls: "bg-slate-700/60 text-slate-300" };
}

// ---------------------------------------------------------------------------
// Loading skeleton
// ---------------------------------------------------------------------------

const Skeleton = memo(function Skeleton() {
  return (
    <div className="rounded-xl border border-gray-800 bg-gray-900 p-4">
      <div className="mb-3 h-5 w-48 animate-pulse rounded bg-gray-700" />
      <div className="space-y-2">
        {[...Array(6)].map((_, i) => (
          <div key={i} className="h-6 animate-pulse rounded bg-gray-800" />
        ))}
      </div>
    </div>
  );
});

// ---------------------------------------------------------------------------
// Analysis badge
// ---------------------------------------------------------------------------

const Badge = memo(function Badge({ label, variant }) {
  const cls = {
    "Extreme Bullish": "bg-emerald-900/70 text-emerald-300 border-emerald-700",
    Bullish:           "bg-emerald-900/40 text-emerald-400 border-emerald-800",
    Caution:           "bg-amber-900/40  text-amber-400  border-amber-800",
    Bearish:           "bg-rose-900/40   text-rose-400   border-rose-800",
    Neutral:           "bg-slate-800     text-slate-400  border-slate-700",
    Oversold:          "bg-rose-900/60   text-rose-300   border-rose-700",
    Overbought:        "bg-amber-900/60  text-amber-300  border-amber-700",
  }[variant] ?? "bg-slate-800 text-slate-400 border-slate-700";

  return (
    <span className={`inline-flex items-center rounded-full border px-2 py-0.5 text-xs font-medium ${cls}`}>
      {label}
    </span>
  );
});

// ---------------------------------------------------------------------------
// Analysis panel (derived from the latest row)
// ---------------------------------------------------------------------------

const AnalysisPanel = memo(function AnalysisPanel({ row }) {
  if (!row) return null;

  const up4 = row.up_4_pct ?? 0;
  const dn4 = row.down_4_pct ?? 0;
  const thrust = dn4 <= 0 ? up4 > 0 : up4 > 3 * dn4;

  const shortTerm = thrust
    ? { label: "Extremely Bullish / Thrust", badge: "Extreme Bullish" }
    : up4 > dn4
    ? { label: "Bulls leading on the 4%+ tape", badge: "Bullish" }
    : { label: "Bears competitive on the 4%+ tape", badge: "Caution" };

  const upQ = row.up_25_q, dnQ = row.down_25_q;
  const quarterly =
    upQ != null && dnQ != null && dnQ > upQ
      ? { label: "Quarterly breadth skewed negative (dn > up)", badge: "Bearish" }
      : { label: "Quarterly breadth not dominated by losers", badge: "Neutral" };

  const t = t2108Badge(row.t2108);

  return (
    <div className="flex flex-wrap gap-3">
      <div className="flex items-center gap-2 text-xs text-slate-400">
        <span>Short-term:</span>
        <Badge label={shortTerm.badge} variant={shortTerm.badge} />
        <span className="text-slate-500">{shortTerm.label}</span>
      </div>
      <div className="flex items-center gap-2 text-xs text-slate-400">
        <span>Quarterly:</span>
        <Badge label={quarterly.badge} variant={quarterly.badge} />
        <span className="text-slate-500">{quarterly.label}</span>
      </div>
      {t && (
        <div className="flex items-center gap-2 text-xs text-slate-400">
          <span>T2108:</span>
          <Badge label={t.label} variant={t.label.startsWith("Over") ? (t.label.includes("sold") ? "Oversold" : "Overbought") : "Neutral"} />
        </div>
      )}
    </div>
  );
});

// ---------------------------------------------------------------------------
// Clickable column map — latest row only
// ---------------------------------------------------------------------------

const CLICKABLE_COLS = {
  up_4_pct:    { filter: "up4",     label: "Up 4%+ Today" },
  down_4_pct:  { filter: "dn4",     label: "Down 4%+ Today" },
  up_25_q:     { filter: "up25q",   label: "Up 25%+ Quarterly" },
  down_25_q:   { filter: "dn25q",   label: "Down 25%+ Quarterly" },
  up_25_m:     { filter: "up25m",   label: "Up 25%+ Monthly" },
  down_25_m:   { filter: "dn25m",   label: "Down 25%+ Monthly" },
  up_50_m:     { filter: "up50m",   label: "Up 50%+ Monthly" },
  down_50_m:   { filter: "dn50m",   label: "Down 50%+ Monthly" },
  up_13_34d:   { filter: "up13_34", label: "Up 13%+ 34-Day" },
  down_13_34d: { filter: "dn13_34", label: "Down 13%+ 34-Day" },
};

// ---------------------------------------------------------------------------
// Main table
// ---------------------------------------------------------------------------

const BreadthTable = memo(function BreadthTable({ rows, onOpenModal }) {
  return (
    <div className="overflow-x-auto">
      <table className="w-full min-w-[1040px] border-collapse text-left">
        <caption className="sr-only">Stockbee Market Monitor breadth history.</caption>
        <thead>
          {/* ── Row 1: group headers ────────────────────────────── */}
          <tr>
            {/* Date — rowSpan=2 */}
            <th rowSpan={2}
                className="sticky left-0 z-10 bg-amber-500 text-black text-xs font-bold px-2 py-1 text-center whitespace-nowrap border border-amber-600 align-middle">
              Date
            </th>
            {/* Primary Breadth Indicators — 4 cols */}
            <th colSpan={4}
                className="bg-amber-400 text-black text-xs font-bold px-1 py-1 text-center border border-amber-500">
              Primary Breadth Indicators
            </th>
            {/* Secondary Breadth Indicators — 8 cols */}
            <th colSpan={8}
                className="bg-emerald-500 text-black text-xs font-bold px-1 py-1 text-center border border-emerald-600">
              Secondary Breadth Indicators
            </th>
            {/* 10x ATR Ext — rowSpan=2 */}
            <th rowSpan={2}
                className="bg-amber-400 text-black text-[10px] font-bold px-1 py-1 text-center whitespace-pre-line border border-amber-500 align-middle leading-tight">
              {"10x ATR\nExt."}
            </th>
            {/* >50dma — rowSpan=2 */}
            <th rowSpan={2}
                className="bg-sky-400 text-black text-[10px] font-bold px-1 py-1 text-center whitespace-nowrap border border-sky-500 align-middle">
              {">50dma"}
            </th>
            {/* Stock Universe — rowSpan=2 */}
            <th rowSpan={2}
                className="bg-violet-400 text-black text-[10px] font-bold px-1 py-1 text-center whitespace-pre-line border border-violet-500 align-middle leading-tight">
              {"Stock\nUniverse"}
            </th>
            {/* T2108 — rowSpan=2 */}
            <th rowSpan={2}
                className="bg-amber-400 text-black text-[10px] font-bold px-1 py-1 text-center whitespace-nowrap border border-amber-500 align-middle">
              T2108
            </th>
            {/* S&P — rowSpan=2 */}
            <th rowSpan={2}
                className="bg-amber-400 text-black text-[10px] font-bold px-1 py-1 text-center whitespace-nowrap border border-amber-500 align-middle">
              S&amp;P
            </th>
          </tr>

          {/* ── Row 2: individual sub-headers ──────────────────── */}
          <tr className="border-b border-gray-700">
            {/* Primary — 4 cols */}
            {[
              "Stocks Up\n4%+ Today",
              "Stocks Down\n4%+ Today",
              "5 Day\nRatio",
              "10 Day\nRatio",
            ].map((label) => (
              <th key={label}
                  className="bg-amber-300 text-black text-[10px] font-semibold px-1 py-1 text-center whitespace-pre-line border border-amber-400 leading-tight">
                {label}
              </th>
            ))}
            {/* Secondary — 8 cols */}
            {[
              "Up 25%+\nQuarter",
              "Down 25%+\nQuarter",
              "Up 25%+\nMonth",
              "Down 25%+\nMonth",
              "Up 50%+\nMonth",
              "Down 50%+\nMonth",
              "Up 13%+\n34 Days",
              "Down 13%+\n34 Days",
            ].map((label) => (
              <th key={label}
                  className="bg-emerald-300 text-black text-[10px] font-semibold px-1 py-1 text-center whitespace-pre-line border border-emerald-400 leading-tight">
                {label}
              </th>
            ))}
          </tr>
        </thead>
        <tbody>
          {rows.map((r, i) => {
            const isLatest = i === 0;
            const bearish = r.up_25_q != null && r.down_25_q != null && r.up_25_q < r.down_25_q;
            const up4hi = r.up_4_pct != null && r.up_4_pct > 600;
            const t2108Low = r.t2108 != null && r.t2108 < 20;

            // Helper: wrap a cell value in a clickable span on the latest row
            const cell = (field, content, extraCls = "") => {
              const col = CLICKABLE_COLS[field];
              if (isLatest && col) {
                return (
                  <td
                    className={`px-1 py-1 text-right whitespace-nowrap cursor-pointer
                      underline decoration-dotted underline-offset-2 hover:text-white ${extraCls}`}
                    onClick={() => onOpenModal(col.filter, col.label)}
                    title={`View ${col.label} stocks`}
                  >
                    {content}
                  </td>
                );
              }
              return <td className={`px-1 py-1 text-right whitespace-nowrap ${extraCls}`}>{content}</td>;
            };

            return (
              <tr
                key={r.date}
                className={`border-b border-gray-800/80 font-mono text-xs ${
                  isLatest ? "bg-gray-800/30" : ""
                } ${bearish ? "text-rose-200/70" : "text-slate-300"}`}
              >
                {/* DATE — sticky */}
                <td className="sticky left-0 z-10 bg-gray-900 py-1 pr-3 font-mono text-xs whitespace-nowrap">
                  {isLatest
                    ? <span className="font-semibold text-emerald-400">{r.date_display}</span>
                    : r.date_display}
                </td>

                {cell("up_4_pct",    fmtN(r.up_4_pct),    up4hi ? "font-semibold text-emerald-300" : "")}
                {cell("down_4_pct",  fmtN(r.down_4_pct))}
                <td className="px-1 py-1 text-right whitespace-nowrap">{fmtN(r.ratio_5d)}</td>
                <td className="px-1 py-1 text-right whitespace-nowrap">{fmtN(r.ratio_10d)}</td>
                {cell("up_25_q",     fmtN(r.up_25_q))}
                {cell("down_25_q",   fmtN(r.down_25_q),   bearish ? "text-rose-400" : "")}
                {cell("up_25_m",     fmtN(r.up_25_m))}
                {cell("down_25_m",   fmtN(r.down_25_m))}
                {cell("up_50_m",     fmtN(r.up_50_m))}
                {cell("down_50_m",   fmtN(r.down_50_m))}
                {cell("up_13_34d",   fmtN(r.up_13_34d))}
                {cell("down_13_34d", fmtN(r.down_13_34d))}

                {/* 10x ATR Ext — clickable on latest row */}
                <td
                  className={`px-1 py-1 text-right whitespace-nowrap font-mono
                    ${isLatest && r.atr_10x_ext != null
                      ? "cursor-pointer underline decoration-dotted underline-offset-2 hover:text-purple-100 text-purple-300"
                      : "text-purple-300"}`}
                  onClick={isLatest && r.atr_10x_ext != null
                    ? () => onOpenModal("atr_ext", "10x ATR Extended")
                    : undefined}
                  title={isLatest && r.atr_10x_ext != null ? "View 10x ATR Extended stocks" : undefined}
                >
                  {r.atr_10x_ext != null ? fmtN(r.atr_10x_ext) : "—"}
                </td>
                {/* >50 DMA — red cell fill when < 30%; clickable on latest row */}
                <td
                  className={`px-1 py-1 text-right whitespace-nowrap font-mono
                    ${r.above_50dma_pct != null && r.above_50dma_pct < 30
                      ? "bg-rose-900/70 text-rose-200 font-semibold"
                      : "text-sky-300"}
                    ${isLatest && r.above_50dma_pct != null
                      ? "cursor-pointer underline decoration-dotted underline-offset-2"
                      : ""}`}
                  onClick={isLatest && r.above_50dma_pct != null
                    ? () => onOpenModal("above50dma", ">50 DMA")
                    : undefined}
                  title={isLatest && r.above_50dma_pct != null ? "View stocks above 50 DMA" : undefined}
                >
                  {r.above_50dma_pct != null ? `${r.above_50dma_pct.toFixed(1)}%` : "—"}
                </td>
                {/* Share Universe */}
                <td className="px-1 py-1 text-right text-amber-300/80 whitespace-nowrap">
                  {fmtN(r.worden_universe)}
                </td>
                {/* T2108 */}
                <td className={`px-1 py-1 text-right whitespace-nowrap ${t2108Low ? "font-semibold text-rose-400" : "text-amber-300/80"}`}>
                  {r.t2108 != null ? `${r.t2108.toFixed(1)}%` : "—"}
                </td>
                {/* S&P */}
                <td className="px-1 py-1 text-right text-amber-300/80 whitespace-nowrap">
                  {fmtN(r.sp_index)}
                </td>
              </tr>
            );
          })}
        </tbody>
      </table>
    </div>
  );
});

// ---------------------------------------------------------------------------
// Main component
// ---------------------------------------------------------------------------

const MarketBreadthMonitor = memo(function MarketBreadthMonitor() {
  const [data, setData]             = useState(null);
  const [loading, setLoading]       = useState(true);
  const [error, setError]           = useState(null);
  const [modal, setModal]           = useState(null); // { filter, label }
  const [clipGroups, setClipGroups] = useState([]);   // [{ id, label, tickers, sentiment }]
  const [clipOpen, setClipOpen]     = useState(false);
  const abortRef                    = useRef(null);

  const openModal  = useCallback((filter, label) => setModal({ filter, label }), []);
  const closeModal = useCallback(() => setModal(null), []);

  // Add a group of tickers to the clipboard
  const addToClipboard = useCallback((label, tickers, filter) => {
    if (!tickers.length) return;
    const sentiment = BULLISH_FILTERS.has(filter) ? "bullish" : "bearish";
    setClipGroups((prev) => {
      // If a group with the same label+sentiment already exists, replace it
      const exists = prev.findIndex((g) => g.label === label && g.sentiment === sentiment);
      if (exists >= 0) {
        const next = [...prev];
        next[exists] = { ...next[exists], tickers: [...new Set([...next[exists].tickers, ...tickers])] };
        return next;
      }
      return [...prev, { id: Date.now(), label, tickers, sentiment }];
    });
    setClipOpen(true);
  }, []);

  const removeGroup = useCallback((id) => {
    setClipGroups((prev) => prev.filter((g) => g.id !== id));
  }, []);

  const clearTab = useCallback((tab) => {
    setClipGroups((prev) => prev.filter((g) => g.sentiment !== tab));
  }, []);

  const totalClipCount = clipGroups.reduce((s, g) => s + g.tickers.length, 0);

  const load = async () => {
    setLoading(true);
    setError(null);
    abortRef.current?.abort();
    const ctrl = new AbortController();
    abortRef.current = ctrl;

    try {
      const res = await fetch(
        `${process.env.PUBLIC_URL}/breadth_monitor.json?_=${Date.now()}`,
        { signal: ctrl.signal }
      );
      if (!res.ok) throw new Error(`HTTP ${res.status}`);
      const json = await res.json();
      setData(json);
    } catch (e) {
      if (e.name === "AbortError") return;
      setError(e.message);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    void load();
    return () => abortRef.current?.abort();
  }, []); // eslint-disable-line react-hooks/exhaustive-deps

  // ── Loading ──────────────────────────────────────────────────────────────
  if (loading) return <Skeleton />;

  // ── Error ────────────────────────────────────────────────────────────────
  if (error || !data) {
    return (
      <div className="rounded-xl border border-rose-900/40 bg-rose-950/20 px-4 py-4 text-sm text-rose-200">
        <p className="font-semibold">Market Monitor unavailable</p>
        <p className="mt-1 text-xs text-rose-300/80">{error ?? "Unknown error"}</p>
        <button
          onClick={() => void load()}
          className="mt-2 text-xs text-slate-400 underline hover:text-slate-200"
        >
          Retry
        </button>
      </div>
    );
  }

  const rows = data.rows ?? [];
  const latest = rows[0] ?? null;

  return (
    <div className="rounded-xl border border-gray-800 bg-gray-900">
      {/* Header */}
      <div className="flex flex-wrap items-center justify-between gap-2 border-b border-gray-800 px-4 py-3">
        <div className="flex items-center gap-2">
          <BarChart3 className="h-4 w-4 text-emerald-400" />
          <div>
            <h3 className="text-sm font-semibold text-slate-100">Stockbee Market Monitor</h3>
            <p className="text-xs text-slate-500">
              Sheet {data.sheet_year ?? "—"} ·{" "}
              {data.fetched_at_utc
                ? `Updated ${new Date(data.fetched_at_utc).toLocaleString()}`
                : "—"}
            </p>
          </div>
        </div>

        <div className="flex items-center gap-3">
          {data.blog_url && (
            <a
              href={data.blog_url}
              target="_blank"
              rel="noopener noreferrer"
              className="flex items-center gap-1 text-xs text-slate-500 hover:text-emerald-400"
            >
              stockbee MM <ExternalLink className="h-3 w-3" />
            </a>
          )}
          <button
            onClick={() => void load()}
            title="Refresh"
            className="flex items-center gap-1 rounded px-2 py-1 text-xs text-slate-400 hover:bg-gray-800 hover:text-slate-200"
          >
            <RefreshCw className="h-3 w-3" />
            Refresh
          </button>

          {/* Clipboard badge */}
          <div className="relative">
            <button
              onClick={() => setClipOpen((o) => !o)}
              title="Watchlist Clipboard"
              className={`relative flex items-center gap-1 rounded px-2 py-1 text-xs transition-colors
                ${clipOpen ? "bg-zinc-700 text-zinc-100" : "text-slate-400 hover:bg-gray-800 hover:text-slate-200"}`}
            >
              <Clipboard className="h-4 w-4" />
              {totalClipCount > 0 && (
                <span className="absolute -right-1.5 -top-1.5 flex h-4 w-4 items-center justify-center rounded-full bg-emerald-500 text-[10px] font-bold text-white leading-none">
                  {totalClipCount > 99 ? "99+" : totalClipCount}
                </span>
              )}
            </button>

            {clipOpen && (
              <WatchlistClipboard
                groups={clipGroups}
                onRemoveGroup={removeGroup}
                onClear={clearTab}
                onClose={() => setClipOpen(false)}
              />
            )}
          </div>
        </div>
      </div>

      {/* Analysis */}
      {latest && (
        <div className="border-b border-gray-800 px-4 py-2">
          <AnalysisPanel row={latest} />
        </div>
      )}

      {/* Table */}
      <div className="p-4">
        {rows.length === 0 ? (
          <p className="text-center text-sm text-slate-500 py-8">No breadth data available.</p>
        ) : (
          <BreadthTable rows={rows} onOpenModal={openModal} />
        )}
      </div>

      {/* Footer note */}
      <div className="border-t border-gray-800 px-4 py-2">
        <p className="text-xs text-slate-600">
          Data from Stockbee Market Monitor spreadsheet. Refreshed daily after market close.
          Click any highlighted cell on the latest row to drill into individual stocks.
          10x ATR Ext and &gt;50 DMA are live from TradingView screener.
        </p>
      </div>

      {/* Drill-down modal */}
      {modal && (
        <BreadthStockModal
          filter={modal.filter}
          filterLabel={modal.label}
          onClose={closeModal}
          onAddToClipboard={addToClipboard}
        />
      )}
    </div>
  );
});

export default MarketBreadthMonitor;
